const source = $json.approved_packet || {};
const bridge = {
  packet_family: 'provider_packet_bridge',
  provider_target: $json.provider_target,
  route_id: $json.route_id,
  replay_reference: {
    workflow: 'WF-022',
    dossier_id: $json.dossier_id,
    timestamp: new Date().toISOString()
  },
  outbound_payload: {
    source_packet_id: source.instance_id || null,
    source_family: source.artifact_family || null,
    body: source.payload || source
  }
};
return [{ json: { ...$json, bridge_packet: bridge } }];

const bridge = $json.bridge_packet || {};
const errs = [];
if (!bridge.provider_target) errs.push('provider_target missing');
if (!bridge.outbound_payload) errs.push('outbound_payload missing');
if (!bridge.replay_reference) errs.push('replay_reference missing');
if (errs.length) throw new Error('WF-022 validation failed: ' + errs.join('; '));
return [{ json: { workflow_id: 'WF-022', status: 'SUCCESS', output_packet_family: 'provider_packet_bridge', provider_packet_bridge: bridge } }];
